/** Evita errores `permission-denied` en consola mientras se desconectan listeners al cerrar sesión. */
let staffPanelLogoutInProgress = false;

function isLogoutPermissionNoise(err) {
  if (!staffPanelLogoutInProgress) return false;
  const code = String(err?.code || '');
  return code === 'permission-denied' || code === 'PERMISSION_DENIED';
}

function logAndEmitFirestoreListenError(err) {
  if (isLogoutPermissionNoise(err)) return;
  console.error(err);
  emitGlobalSystemAlert(shortFirebaseClientMessage(err), { tone: 'warn', ms: 6800 });
}

function firestoreListenConsoleError(err) {
  if (isLogoutPermissionNoise(err)) return;
  console.error(err);
}

/** Clave antigua (global); se migra una vez al iniciar sesión a `darkModeStorageKeyForUid`. */
const DARK_MODE_LEGACY_KEY = 'vnpm-theme-dark';
const LAST_ROUTE_LEGACY_KEY = 'vnpm-last-route';

function darkModeStorageKeyForUid(uid) {
  return uid ? `vnpm-theme-dark:${uid}` : '';
}

function readStoredDarkModeForUid(uid) {
  if (!uid || typeof window === 'undefined') return false;
  try {
    return window.localStorage.getItem(darkModeStorageKeyForUid(uid)) === '1';
  } catch {
    return false;
  }
}

function migrateLegacyDarkModeToUid(uid) {
  if (!uid || typeof window === 'undefined') return;
  try {
    const perUserKey = darkModeStorageKeyForUid(uid);
    if (window.localStorage.getItem(DARK_MODE_LEGACY_KEY) === '1' && window.localStorage.getItem(perUserKey) == null) {
      window.localStorage.setItem(perUserKey, '1');
    }
    window.localStorage.removeItem(DARK_MODE_LEGACY_KEY);
  } catch {
    /* ignore */
  }
}

function lastRouteStorageKeyForUid(uid) {
  return uid ? `vnpm-last-route:${uid}` : '';
}

function readStoredRouteForUid(uid) {
  if (!uid || typeof window === 'undefined') return null;
  try {
    const raw = window.localStorage.getItem(lastRouteStorageKeyForUid(uid));
    if (!raw) return null;
    const parsed = JSON.parse(raw);
    const pathname = String(parsed?.pathname || '').trim();
    if (!pathname || pathname === '/login') return null;
    const scrollY = Number(parsed?.scrollY);
    return { pathname, scrollY: Number.isFinite(scrollY) && scrollY > 0 ? scrollY : 0 };
  } catch {
    return null;
  }
}

function migrateLegacyRouteToUid(uid) {
  if (!uid || typeof window === 'undefined') return;
  try {
    const perUserKey = lastRouteStorageKeyForUid(uid);
    if (window.localStorage.getItem(LAST_ROUTE_LEGACY_KEY) && window.localStorage.getItem(perUserKey) == null) {
      window.localStorage.setItem(perUserKey, window.localStorage.getItem(LAST_ROUTE_LEGACY_KEY));
    }
    window.localStorage.removeItem(LAST_ROUTE_LEGACY_KEY);
  } catch {
    /* ignore */
  }
}

const LOGS_SESSION_CACHE_MAX = 2500;
const LOGS_SESSION_CACHE_KEY = "vnpm_logs_cache";
/** Caché de logs revertibles por sesión de depuración (sessionStorage). */
const debugRevertStorageKey = (sessionId) => `vnpm_debug_revert_${String(sessionId)}`;

/**
 * Al revertir un `app_events` con `setDoc(previousData)`, un `previousData` capturado antes
 * de que el snapshot actualizara el estado puede omitir sedes añadidas al evento (p. ej. Querétaro/Neza).
 * Se conserva la unión de sedes entre el snapshot revertido y el documento actual.
 */
function mergeAppEventDocForRevert(previousData, currentData, docId) {
  const prev = previousData && typeof previousData === 'object' ? { ...previousData } : {};
  const cur = currentData && typeof currentData === 'object' ? currentData : {};
  const locSet = new Set(
    [...(Array.isArray(prev.locations) ? prev.locations : []), ...(Array.isArray(cur.locations) ? cur.locations : [])]
      .map((x) => String(x).trim())
      .filter(Boolean)
  );
  const { id: _dropId, ...prevRest } = prev;
  return omitUndefinedDeep({
    ...prevRest,
    id: String(docId || prev.id || '').trim() || docId,
    locations: [...locSet],
    regStatus: { ...(cur.regStatus || {}), ...(prev.regStatus || {}) },
    locationCaps: { ...(cur.locationCaps || {}), ...(prev.locationCaps || {}) },
    cardPaymentByLocation: { ...(cur.cardPaymentByLocation || {}), ...(prev.cardPaymentByLocation || {}) },
  });
}

/** Añade al evento de respaldo sedes que aparecen en participantes pero faltan en `events[].locations`. */
function enrichBackupEventsWithParticipantLocations(events, participants) {
  return (events || []).map((ev) => {
    const locSet = new Set(
      (Array.isArray(ev.locations) ? ev.locations : []).map((x) => String(x).trim()).filter(Boolean)
    );
    for (const p of participants || []) {
      if (String(p?.eventId || '') !== String(ev?.id || '')) continue;
      const loc = String(p?.location ?? '').trim();
      if (loc) locSet.add(loc);
    }
    if (locSet.size === 0) return ev;
    return { ...ev, locations: [...locSet] };
  });
}

/** Clon de `snapshot.data()` para `revertInfo.previousData` (revertir con `setDoc` completo). */
function cloneFirestoreDocDataForRevert(raw) {
  if (raw == null || typeof raw !== 'object') return null;
  if (typeof structuredClone === 'function') {
    try {
      return structuredClone(raw);
    } catch {
      /* no clonable */
    }
  }
  try {
    return JSON.parse(JSON.stringify(raw));
  } catch {
    return { ...raw };
  }
}

/** Consultas recientes ordenadas por tiempo (documentos sin `createdAt` no aparecen aquí; sí en búsqueda completa). */
const LOGS_ORDER_FIELD = 'createdAt';
const LOGS_SERVER_CHUNK = 500;
const LOGS_STORAGE_MAX_DEFAULT = 10000;
const LOGS_STORAGE_MAX_MIN = 1000;
const LOGS_STORAGE_MAX_HARD_MAX = 50000;
/** Prefetch de logs en segundo plano (0 = desactivado; ahorra lecturas si no abres «Actividad»). */
const LOGS_BACKGROUND_PREFETCH = 0;
/** Evita listeners que solo reflejan cambios de metadatos locales (menos trabajo en cliente). */
const SNAPSHOT_LISTENER_OPTS = { includeMetadataChanges: false };
const LOGS_TOTAL_COUNT_STALE_MS = 5 * 60 * 1000;

function logsUseVisibleInPanelQuery(configLike) {
  return Boolean(configLike?.logsVisibleInPanelBackfillAt);
}

function buildLogsRecentOrderQuery(cursor, take, useVisibleInPanel) {
  const col = getColRef('app_logs');
  if (useVisibleInPanel) {
    return cursor
      ? query(
          col,
          where('visibleInPanel', '==', true),
          orderBy(LOGS_ORDER_FIELD, 'desc'),
          startAfter(cursor),
          limit(take)
        )
      : query(col, where('visibleInPanel', '==', true), orderBy(LOGS_ORDER_FIELD, 'desc'), limit(take));
  }
  return cursor
    ? query(col, orderBy(LOGS_ORDER_FIELD, 'desc'), startAfter(cursor), limit(take))
    : query(col, orderBy(LOGS_ORDER_FIELD, 'desc'), limit(take));
}

async function fetchDebugSessionLogs(debugSessionId) {
  const sid = String(debugSessionId || '').trim();
  if (!sid) return [];
  const col = getColRef('app_logs');
  const out = new Map();
  let cursor = null;
  for (let b = 0; b < 40; b++) {
    const q = cursor
      ? query(
          col,
          where('debugSessionId', '==', sid),
          where('isDebug', '==', true),
          orderBy(LOGS_ORDER_FIELD, 'desc'),
          startAfter(cursor),
          limit(LOGS_SERVER_CHUNK)
        )
      : query(
          col,
          where('debugSessionId', '==', sid),
          where('isDebug', '==', true),
          orderBy(LOGS_ORDER_FIELD, 'desc'),
          limit(LOGS_SERVER_CHUNK)
        );
    const snap = await getDocsFromServer(q);
    if (snap.empty) break;
    for (const d of snap.docs) out.set(String(d.id), { id: d.id, ...d.data() });
    cursor = snap.docs[snap.docs.length - 1];
    if (snap.docs.length < LOGS_SERVER_CHUNK) break;
  }
  return mergeLogsDedupById([[...out.values()]]);
}

function persistLogsToSessionCache(entries) {
  try {
    const toStore = entries.slice(0, LOGS_SESSION_CACHE_MAX);
    sessionStorage.setItem(LOGS_SESSION_CACHE_KEY, JSON.stringify({ ts: Date.now(), entries: toStore }));
  } catch (_) {
    /* quota u otro */
  }
}

function clearLogsSessionCache() {
  try {
    sessionStorage.removeItem(LOGS_SESSION_CACHE_KEY);
  } catch (_) {}
}

/** Comprueba si el ID VNPM ya existe en cualquier evento (sin depender de tener toda la colección en memoria). */
async function vnpPersonIdExistsInFirestore(vnpId) {
  const id = String(vnpId || '').trim();
  if (!id) return false;
  const q = query(getColRef('app_participants'), where('vnpPersonId', '==', id), limit(1));
  const snap = await getDocs(q);
  return !snap.empty;
}

/** Evita expandir/colapsar la fila cuando el clic fue en un control (botón, enlace, formulario). */
const isRosterRowInteractiveClickTarget = (target) => {
  if (typeof Element === 'undefined' || !(target instanceof Element)) return false;
  return Boolean(
    target.closest('button, a, input, select, textarea, label, [role="button"], [contenteditable="true"]')
  );
};

/** Ids de filas derivadas (beca / saldo a favor) generadas en cliente para la lista de gastos. */
function isScholarshipAutoExpenseIdForEvent(id, eventId) {
  if (!eventId || !id) return false;
  return id === `sch-auto-approved-${eventId}` || id === `sch-auto-pending-${eventId}`;
}
function isManualCreditVirtualExpenseIdForEvent(id, eventId) {
  if (!eventId || !id || typeof id !== 'string') return false;
  return id.startsWith('manual-credit-') && id.endsWith(`-${eventId}`);
}
function isDerivedAutoExpenseIdForEvent(id, eventId) {
  return isScholarshipAutoExpenseIdForEvent(id, eventId) || isManualCreditVirtualExpenseIdForEvent(id, eventId);
}

/** Subcolección de trozos (legado `formatVersion: 2`); ya no se escribe en copias nuevas. */
const getBackupChunksColRef = (backupId) =>
  collection(db, 'app_backups', backupId, 'chunks');

const BACKUP_STORAGE_PREFIX = 'app_auto_backups';
/** Copias con más de este número de meses (por fecha del id `YYYY-MM-DD`) se borran de Storage + Firestore. */
const BACKUP_RETENTION_MONTHS = 3;

/** Evita solapes del efecto de copia (p. ej. React StrictMode o deps que disparan varias veces seguidas). */
let scheduledBackupAsyncLock = false;

/** Objetos planos `{}` (no Timestamp, Date, DocumentReference, etc.). */
const isPlainObject = (v) =>
  v !== null && typeof v === 'object' && !Array.isArray(v) && Object.getPrototypeOf(v) === Object.prototype;

function clampLogsStorageLimit(raw) {
  const n = Math.floor(Number(raw));
  if (!Number.isFinite(n)) return LOGS_STORAGE_MAX_DEFAULT;
  return Math.max(LOGS_STORAGE_MAX_MIN, Math.min(LOGS_STORAGE_MAX_HARD_MAX, n));
}

/**
 * Firestore rechaza `undefined` en setDoc/updateDoc/batch.set; elimina claves undefined en profundidad.
 * No atraviesa instancias no planas (Timestamp, Date, GeoPoint, DocumentReference…) para no corromperlas.
 */
const omitUndefinedDeep = (input) => {
  if (input === undefined) return undefined;
  if (input === null || typeof input !== 'object') return input;
  if (Array.isArray(input)) {
    return input.map(omitUndefinedDeep).filter((x) => x !== undefined);
  }
  if (!isPlainObject(input)) return input;
  const out = {};
  for (const [k, v] of Object.entries(input)) {
    if (v === undefined) continue;
    const next = omitUndefinedDeep(v);
    if (next !== undefined) out[k] = next;
  }
  return out;
};

const FIRESTORE_BATCH_LIMIT = 500;

const deleteAllDocsInCollection = async (colRef) => {
  const snap = await getDocs(colRef);
  if (snap.empty) return;
  let batch = writeBatch(db);
  let count = 0;
  for (const d of snap.docs) {
    batch.delete(d.ref);
    count += 1;
    if (count >= 500) {
      await batch.commit();
      batch = writeBatch(db);
      count = 0;
    }
  }
  if (count > 0) await batch.commit();
};

/** Borrados en lotes de hasta 500 (límite de `writeBatch`). */
const commitDeleteRefsInBatches = async (refs) => {
  if (!refs.length) return;
  for (let i = 0; i < refs.length; i += FIRESTORE_BATCH_LIMIT) {
    const batch = writeBatch(db);
    for (const r of refs.slice(i, i + FIRESTORE_BATCH_LIMIT)) {
      batch.delete(r);
    }
    await batch.commit();
  }
};

/** Escrituras `set` en lotes de hasta 500, en orden (sin miles de peticiones en paralelo). */
const commitSetPayloadsInBatches = async (entries) => {
  if (!entries.length) return;
  for (let i = 0; i < entries.length; i += FIRESTORE_BATCH_LIMIT) {
    const batch = writeBatch(db);
    for (const { ref, data } of entries.slice(i, i + FIRESTORE_BATCH_LIMIT)) {
      batch.set(ref, omitUndefinedDeep(data));
    }
    await batch.commit();
  }
};

/** Copia automática: JSON en Storage (`app_auto_backups/{id}.json`) y manifest en `app_backups/{id}` (`formatVersion: 3`). */
const writeAppBackupToStorage = async (backupId, { date, timestamp, participants, events, users }) => {
  await deleteAllDocsInCollection(getBackupChunksColRef(backupId));
  const payload = omitUndefinedDeep({
    date,
    timestamp,
    participants,
    events,
    users,
  });
  const jsonStr = JSON.stringify(payload);
  const path = `${BACKUP_STORAGE_PREFIX}/${backupId}.json`;
  await uploadString(storageRef(storage, path), jsonStr, 'raw', {
    contentType: 'application/json; charset=utf-8',
  });
  await setDoc(
    getDocRef('app_backups', backupId),
    omitUndefinedDeep({
      date,
      timestamp,
      formatVersion: 3,
      storagePath: path,
      storageSizeUtf8: new TextEncoder().encode(jsonStr).length,
    })
  );
};

/** Elimina copias con id de fecha anterior al corte (mismo esquema `YYYY-MM-DD`). */
const pruneAppBackupsOlderThanRetention = async (nowDate, monthsToKeep) => {
  const cutoff = new Date(nowDate.getFullYear(), nowDate.getMonth() - monthsToKeep, nowDate.getDate());
  const cutoffStr = `${cutoff.getFullYear()}-${String(cutoff.getMonth() + 1).padStart(2, '0')}-${String(cutoff.getDate()).padStart(2, '0')}`;
  const listSnap = await getDocs(collection(db, 'app_backups'));
  for (const docSnap of listSnap.docs) {
    if (String(docSnap.id) >= cutoffStr) continue;
    const meta = docSnap.data() || {};
    try {
      if (Number(meta.formatVersion) === 3 && meta.storagePath) {
        await deleteObject(storageRef(storage, meta.storagePath)).catch(() => {});
        await deleteDoc(docSnap.ref);
      } else if (Number(meta.formatVersion) === 2) {
        await deleteAllDocsInCollection(getBackupChunksColRef(docSnap.id));
        await deleteDoc(docSnap.ref);
      } else {
        await deleteDoc(docSnap.ref);
      }
    } catch (e) {
      console.warn('Poda de copia antigua omitida:', docSnap.id, e);
    }
  }
};

/** Martes en hora local (0=dom … 2=martes). */
const isTuesdayLocal = (d) => d.getDay() === 2;

/** Lee copia: Storage (`formatVersion: 3`), trozos Firestore (`formatVersion: 2`) o doc único legado. */
const loadAppBackupMerged = async (backupId) => {
  const snap = await getDoc(getDocRef('app_backups', backupId));
  if (!snap.exists()) return null;
  const data = snap.data();
  if (Number(data.formatVersion) === 3 && data.storagePath) {
    const bytes = await getBytes(storageRef(storage, data.storagePath));
    const text = new TextDecoder('utf-8').decode(bytes);
    const parsed = JSON.parse(text);
    return {
      date: parsed.date ?? data.date,
      timestamp: parsed.timestamp ?? data.timestamp,
      participants: Array.isArray(parsed.participants) ? parsed.participants : [],
      events: Array.isArray(parsed.events) ? parsed.events : [],
      users: Array.isArray(parsed.users) ? parsed.users : [],
    };
  }
  if (data.formatVersion !== 2) {
    return data;
  }
  const chunksCol = getBackupChunksColRef(backupId);
  const qsnap = await getDocs(chunksCol);
  const buckets = { participants: [], events: [], users: [] };
  qsnap.forEach((d) => {
    const c = d.data();
    const k = c.kind;
    if (!buckets[k]) return;
    buckets[k].push({ index: c.index ?? 0, items: Array.isArray(c.items) ? c.items : [] });
  });
  const merge = (arr) =>
    arr.sort((a, b) => a.index - b.index).flatMap((x) => x.items);
  return {
    date: data.date,
    timestamp: data.timestamp,
    participants: merge(buckets.participants),
    events: merge(buckets.events),
    users: merge(buckets.users),
  };
};

/** Ventana para considerar una sesión «activa» (debe ser > intervalo de heartbeat). */
const SESSION_TTL_MS = 90000;
/**
 * Heartbeat para mantener viva la sesión en Firestore. Menos frecuencia = menos escrituras;
 * debe seguir siendo claramente menor que SESSION_TTL_MS para no caducar la sesión.
 */
const SESSION_HEARTBEAT_MS = 45000;

/** ID único por pestaña (sessionStorage); al cerrar la pestaña desaparece, pero el doc en Firestore se borra en pagehide. */
const getTabSessionId = () => {
  try {
    let id = sessionStorage.getItem('vnpm_tab_session_id');
    if (!id) {
      id = typeof crypto !== 'undefined' && crypto.randomUUID ? crypto.randomUUID() : `s_${Date.now()}_${Math.random().toString(36).slice(2, 11)}`;
      sessionStorage.setItem('vnpm_tab_session_id', id);
    }
    return id;
  } catch {
    return `fallback_${Date.now()}_${Math.random().toString(36).slice(2, 9)}`;
  }
};

const sessionDocId = (userId, tabSessionId) => `${String(userId)}_${tabSessionId}`;

const countOtherActiveSessions = async (userId, myTabSessionId) => {
  const q = query(getColRef('app_sessions'), where('userId', '==', String(userId)));
  const snap = await getDocs(q);
  const now = Date.now();
  let n = 0;
  snap.forEach((d) => {
    const data = d.data();
    if (data.sessionId === myTabSessionId) return;
    if ((data.lastHeartbeat || 0) > now - SESSION_TTL_MS) n += 1;
  });
  return n;
};

/** Límite por cuenta en `app_users` (1–20); solo aplica a rol Administrador. */
const clampAdminMaxConcurrentSessions = (raw) => {
  const n = Number(raw);
  if (!Number.isFinite(n)) return 1;
  return Math.max(1, Math.min(20, Math.floor(n)));
};

/** SuperUsuario: sin tope. Administrador: `maxConcurrentSessions` en el perfil. Editor/Lector: una sesión. */
const getMaxConcurrentSessionsForUser = (user) => {
  if (!user) return 1;
  if (user.role === 'SuperUsuario') return Infinity;
  if (user.role === 'Administrador') return clampAdminMaxConcurrentSessions(user.maxConcurrentSessions ?? 1);
  return 1;
};

const BLOOD_TYPE_OTHER_KEY = BLOOD_TYPE_STATS_OTHER;
const BLOOD_BAR_BG_CLASSES = [
  'bg-red-600',
  'bg-rose-600',
  'bg-orange-600',
  'bg-amber-600',
  'bg-pink-600',
  'bg-fuchsia-600',
  'bg-red-700',
  'bg-orange-700',
];
const GENDERS = ["Hombre", "Mujer"];
/** Desayuno Conferencia u otros tipos cuyo nombre incluya «desayuno»: no se solicita transporte en formularios. */
const eventTypeIsDesayuno = (eventType) => String(eventType || '').toLowerCase().includes('desayuno');
const RESPONSIVA_STATUSES = ["Pendiente", "Entregada"];
/** Separación en el matiz para muchas sedes sin repetir el mismo par de tonos seguidos. */
const LOCATION_CHART_GOLDEN_HUE = 137.508;

/**
 * Un color HSL distinto por cada sede del evento (orden estable por nombre).
 * Escala a cualquier cantidad de sedes; nuevas sedes reciben huecos nuevos en el círculo.
 */
const buildLocationChartColorMap = (locations) => {
  const list = [...(locations || [])].filter((x) => x != null && String(x).trim() !== '');
  const sorted = [...list].sort((a, b) => String(a).localeCompare(String(b), 'es'));
  const map = new Map();
  const n = sorted.length;
  sorted.forEach((loc, i) => {
    const h = n <= 1 ? 210 : (i * LOCATION_CHART_GOLDEN_HUE) % 360;
    map.set(loc, `hsl(${h.toFixed(1)} 68% 50%)`);
  });
  return map;
};

/** Teens | Jóvenes si servidor Ambos eligió precio mixto; cadena vacía si tarifa única o no aplica. */
const getAmbosServeInSegmentOrEmpty = (personLike) => {
  const mix = String(personLike?.ambosServeInSegment || '').trim();
  return mix === 'Teens' || mix === 'Jóvenes' ? mix : '';
};

/** Campaña de descuento aplica al perfil servidor/campista del registro. */
const campaignMatchesPersonProfile = (c, personLike) => {
  const isAnyServerAmbos =
    isSiValue(personLike?.isServer) && String(personLike?.serverAssignment || '').trim() === 'Ambos';
  const isServerAmbosTarifaUnica = isAnyServerAmbos && !getAmbosServeInSegmentOrEmpty(personLike);
  const appliesTo = c?.appliesTo || 'all';
  if (appliesTo === 'server_ambos') return isServerAmbosTarifaUnica;
  if (appliesTo === 'general') return !isAnyServerAmbos;
  return true;
};

const isDiscountCampaignVigenteOnDate = (c, dayIso) => {
  if (!c?.startDate || !c?.endDate || !dayIso) return false;
  return c.startDate <= dayIso && dayIso <= c.endDate;
};

/** Inicio y fin definidos; puede activarse sola por calendario (vigencia). Si falta alguna, solo manual (alta/edición). */
const discountCampaignHasDateRange = (c) =>
  !!(c?.startDate && String(c.startDate).trim() && c?.endDate && String(c.endDate).trim());

const isValidDiscountCampaignRow = (c) =>
  !!(
    c &&
    c.enabled !== false &&
    String(c.concept || '').trim() &&
    (Number(c.finalAmount) || 0) > 0
  );

const getValidDiscountCampaignsForPerson = (eventLike, personLike) => {
  const all = Array.isArray(eventLike?.discountCampaigns) ? eventLike.discountCampaigns : [];
  return all.filter((c) => isValidDiscountCampaignRow(c) && campaignMatchesPersonProfile(c, personLike));
};

const discountCampaignAppliesToLabel = (c) => {
  const a = c?.appliesTo || 'all';
  if (a === 'server_ambos') return 'Solo servidor Ambos (tarifa única)';
  if (a === 'general') return 'Campistas y servidores no-Ambos';
  return 'Todos los perfiles';
};

const findDiscountCampaignById = (eventLike, id) => {
  if (id == null || id === '') return null;
  const all = Array.isArray(eventLike?.discountCampaigns) ? eventLike.discountCampaigns : [];
  return all.find((x) => String(x.id) === String(id)) || null;
};

/** Segmento Teens / Jóvenes donde contabilizar el bautizo (evento). Servidor: sigue serverAssignment (un adulto puede servir en Teens). Campista: edad o campAssignment. Null si no aplica o falta dato (ej. Ambos sin elegir). */
const getBaptismAccountingSegment = (personLike) => {
  if (!isSiValue(personLike?.willBeBaptized)) return null;
  const isServer = isSiValue(personLike?.isServer);
  if (isServer) {
    const sa = String(personLike?.serverAssignment || '').trim();
    if (sa === 'Ambos') {
      const bs = String(personLike?.baptismSegment || '').trim();
      return bs === 'Teens' || bs === 'Jóvenes' ? bs : null;
    }
    if (sa === 'Teens' || sa === 'Jóvenes') return sa;
    return null;
  }
  const camp = String(personLike?.campAssignment || '').trim();
  if (camp === 'Teens' || camp === 'Jóvenes') return camp;
  const ageNum = parseInt(personLike?.age, 10) || 0;
  return ageNum < 18 ? 'Teens' : 'Jóvenes';
};

/**
 * Segmento del campamento para el dashboard (Teens / Jóvenes / Ambos): incluye campistas, servidores, becados, cortesías, empleados, etc.
 * Servidor: `serverAssignment`; si falta, campAssignment o edad. Campista: `campAssignment` o edad.
 */
const getCampaAttendanceSegment = (person) => {
  const ageNum = parseInt(person?.age, 10) || 0;
  if (isSiValue(person?.isServer)) {
    const sa = String(person?.serverAssignment || '').trim();
    if (sa === 'Ambos') {
      const mix = getAmbosServeInSegmentOrEmpty(person);
      if (mix === 'Teens' || mix === 'Jóvenes') return mix;
      return 'Ambos';
    }
    if (sa === 'Teens' || sa === 'Jóvenes') return sa;
    const camp = String(person?.campAssignment || '').trim();
    if (camp === 'Teens' || camp === 'Jóvenes') return camp;
    return ageNum < 18 ? 'Teens' : 'Jóvenes';
  }
  const assignment = String(person?.campAssignment || '').trim();
  if (assignment === 'Teens' || assignment === 'Jóvenes') return assignment;
  return ageNum < 18 ? 'Teens' : 'Jóvenes';
};

/**
 * Filtro Teens/Jóvenes del dashboard (Todos / Solo Teens / Solo Jóvenes).
 * Asignación «Ambos» tarifa única cuenta en ambos; Ambos con sirve en Teens/Jóvenes solo en ese segmento.
 */
const campaAttendanceScopeMatches = (isCampaEvent, person, scope) => {
  if (!isCampaEvent || scope === 'all' || scope == null || scope === '') return true;
  const seg = getCampaAttendanceSegment(person);
  if (scope === 'teens') return seg === 'Teens' || seg === 'Ambos';
  if (scope === 'jovenes') return seg === 'Jóvenes' || seg === 'Ambos';
  return true;
};

const NO_SERVICE_LABEL = 'Fuera de servicios dominicales';

/**
 * Horarios de servicio (Primero/Segundo/Tercero) por sede.
 * Prioridad: config global `cashCutScheduleByLocation` (única para todos los eventos) → evento → legado + `serviceSlots`.
 */
const getCashCutScheduleForLocation = (
  event,
  locName,
  globalSlots = DEFAULT_SERVICE_SLOTS,
  globalScheduleByLocation = null,
) => {
  const scheduleFromRaw = (raw) => {
    if (!raw || typeof raw !== 'object') return null;
    const out = {};
    for (const s of SERVICE_OPTIONS) {
      const slot = raw[s];
      if (slot && typeof slot.start === 'string' && typeof slot.end === 'string' && slot.start && slot.end) {
        out[s] = { start: slot.start, end: slot.end };
      }
    }
    return Object.keys(out).length > 0 ? out : null;
  };

  const fromGlobal = scheduleFromRaw(globalScheduleByLocation?.[locName]);
  if (fromGlobal) return fromGlobal;

  const fromEvent = scheduleFromRaw(event?.cashCutScheduleByLocation?.[locName]);
  if (fromEvent) return fromEvent;

  const legacy = event?.cashCutServicesByLocation?.[locName];
  const list =
    Array.isArray(legacy) && legacy.length
      ? SERVICE_OPTIONS.filter((s) => legacy.includes(s))
      : [...SERVICE_OPTIONS];
  const out = {};
  for (const s of list) {
    out[s] = {
      start: globalSlots[s]?.start || DEFAULT_SERVICE_SLOTS[s].start,
      end: globalSlots[s]?.end || DEFAULT_SERVICE_SLOTS[s].end,
    };
  }
  return out;
};

/** Servicios de corte de caja por sede (subset ordenado de SERVICE_OPTIONS). */
const getCashCutServicesForLocation = (
  event,
  locName,
  globalSlots = DEFAULT_SERVICE_SLOTS,
  globalScheduleByLocation = null,
) => {
  const sched = getCashCutScheduleForLocation(event, locName, globalSlots, globalScheduleByLocation);
  return SERVICE_OPTIONS.filter((s) => sched[s]);
};

/** Columnas a mostrar: configuración ∪ servicios que ya aparecen en pagos de esa sede. */
const getCashCutServiceColumnsForLocation = (
  event,
  locName,
  paymentsForCut,
  globalSlots = DEFAULT_SERVICE_SLOTS,
  globalScheduleByLocation = null,
) => {
  const configured = new Set(getCashCutServicesForLocation(event, locName, globalSlots, globalScheduleByLocation));
  const fromData = new Set();
  for (const p of paymentsForCut || []) {
    if (String(p._loc || '') !== String(locName || '')) continue;
    const s = p.service;
    if (SERVICE_OPTIONS.includes(s)) fromData.add(s);
  }
  const union = new Set([...configured, ...fromData]);
  return SERVICE_OPTIONS.filter((s) => union.has(s));
};

const aggregateCashCutPaymentsForLocAndService = (payments, loc, svc) => {
  let efectivo = 0;
  let tarjeta = 0;
  let total = 0;
  let totalNet = 0;
  let count = 0;
  for (const p of payments || []) {
    if (loc != null && String(p._loc || '') !== String(loc || '')) continue;
    const ps = p.service || NO_SERVICE_LABEL;
    if (ps !== svc) continue;
    const amt = parseFloat(p.amount) || 0;
    const net = parseFloat(p.netAmount ?? p.amount) || 0;
    total += amt;
    totalNet += net;
    count += 1;
    if (p.method === 'Tarjeta') tarjeta += amt;
    else efectivo += amt;
  }
  return { efectivo, tarjeta, total, totalNet, count };
};

/** Total del día (todos los servicios) para una sede en corte de caja. */
const aggregateCashCutPaymentsForLoc = (payments, loc) => {
  let efectivo = 0;
  let tarjeta = 0;
  let total = 0;
  let totalNet = 0;
  let count = 0;
  for (const p of payments || []) {
    if (loc != null && String(p._loc || '') !== String(loc || '')) continue;
    const amt = parseFloat(p.amount) || 0;
    const net = parseFloat(p.netAmount ?? p.amount) || 0;
    total += amt;
    totalNet += net;
    count += 1;
    if (p.method === 'Tarjeta') tarjeta += amt;
    else efectivo += amt;
  }
  return { efectivo, tarjeta, total, totalNet, count };
};

/** Rubros fuera de Primero/Segundo/Tercero con movimientos en una sede. */
const getOffScheduleServiceKeysForLocation = (payments, loc) => {
  const keys = new Set();
  for (const p of payments || []) {
    if (String(p._loc || '') !== String(loc || '')) continue;
    const s = p.service || NO_SERVICE_LABEL;
    if (!SERVICE_OPTIONS.includes(s)) keys.add(s);
  }
  return [...keys].sort((a, b) => String(a).localeCompare(String(b), 'es'));
};
const DEFAULT_SERVE_AREA_OPTIONS = ['Jueces', 'Capitanes', 'Staff', 'Seguridad', 'Otro'];
const DEFAULT_ALLERGY_OPTIONS = ['Alimentos', 'Medicamentos', 'Ambientales', 'Insectos', 'Otra'];

const parsePreferredServeArea = (str, knownOpts = DEFAULT_SERVE_AREA_OPTIONS) => {
  const selected = new Set();
  let otroText = '';
  if (!str || typeof str !== 'string') return { selected, otroText };
  const parts = str.split(',').map(p => p.trim()).filter(Boolean);
  for (const p of parts) {
    if (p === 'Otro') selected.add('Otro');
    else if (p.startsWith('Otro: ')) { selected.add('Otro'); otroText = p.slice(6).trim(); }
    else if (knownOpts.includes(p)) selected.add(p);
    else { selected.add('Otro'); otroText = p; } // legacy free text → Otro
  }
  return { selected, otroText };
};

const formatPreferredServeArea = (selected, otroText) => {
  const arr = [...selected].filter(x => x !== 'Otro');
  if (selected.has('Otro')) arr.push(otroText ? `Otro: ${otroText}` : 'Otro');
  return arr.join(', ');
};
// Horarios por defecto (24h). «Segundo» de 11 a 13; «Tercero» de 13 a 17.
const DEFAULT_SERVICE_SLOTS = {
  Primero: { start: '07:00', end: '11:00' },
  Segundo: { start: '11:00', end: '13:00' },
  Tercero: { start: '13:00', end: '17:00' },
};

const defaultLocations = ["Norte", "Sur", "Izcalli", "Coapa", "Acapulco", "Toluca"];
const defaultRegStatus = defaultLocations.reduce((acc, loc) => ({ ...acc, [loc]: true }), {});

/** Campa: asistencia sin cobro (sí cuentan en registro). Mutuamente excluyente con beca. */
const ATTENDANCE_SPECIAL = { ninguno: 'ninguno', empleado: 'empleado', cortesia: 'cortesia' };
const isFreeAttendanceType = (t) => t === ATTENDANCE_SPECIAL.empleado || t === ATTENDANCE_SPECIAL.cortesia;
const normalizeAttendanceSpecial = (personLike) => {
  const t = personLike?.attendanceSpecialType;
  if (t === ATTENDANCE_SPECIAL.empleado || t === ATTENDANCE_SPECIAL.cortesia) return t;
  return ATTENDANCE_SPECIAL.ninguno;
};

/** Restante por liquidar para filtros de lista (0 ⇒ liquidado: sin costo, beca total, cortesía/empleado o pagado al día). */
const getRosterLiquidationRemainder = (person, getLiquidationTargetFn) => {
  const target = Number(getLiquidationTargetFn(person)) || 0;
  const paid = parseFloat(person?.paid || 0) || 0;
  return Math.max(0, target - paid);
};

const isRosterPersonLiquidadoForFilter = (person, getLiquidationTargetFn) =>
  getRosterLiquidationRemainder(person, getLiquidationTargetFn) < 0.005;

/** Pagó más que el objetivo de liquidación (saldo a favor). */
const isRosterSaldoAFavor = (person, getLiquidationTargetFn) => {
  const target = Number(getLiquidationTargetFn(person)) || 0;
  const paid = parseFloat(person?.paid || 0) || 0;
  return paid > target + 0.005;
};

/** Valor interno canúnico (sin tilde) para guardar y comparar con isSiValue(). */
const SI = 'Si';

/** Compara beca/servidor/bautizo/etc.; acepta "Si", "Sí" y datos legacy. */
const isSiValue = (v) => {
  const s = String(v ?? '').trim();
  if (s === SI || s === SI_LABEL) return true;
  if (s.toLowerCase() === 's\u00ed') return true;
  if (s.length === 2 && s[0] === 'S' && (s[1] === '?' || s[1] === '\uFFFD')) return true;
  return false;
};

/** Texto de UI para un campo Si/No (muestra SI_LABEL o "No"). */
const formatSiNo = (v) => (isSiValue(v) ? SI_LABEL : 'No');

/** Comentarios generales del registro: `registrationComments` y filas legacy `paymentHistory` con `kind: 'comment'`. */
function getGeneralRegistrationCommentsForDisplay(person) {
  const fromField = Array.isArray(person?.registrationComments)
    ? person.registrationComments.map((c) => ({ ...c, _source: 'field' }))
    : [];
  const legacy = [];
  (person?.paymentHistory || []).forEach((h, fullIdx) => {
    if (!h || h.kind !== 'comment') return;
    legacy.push({
      id: h.id != null ? h.id : `leg_idx_${fullIdx}`,
      text: h.commentText || h.comment || '',
      createdAt: h.recordedAt ? new Date(h.recordedAt).getTime() : Date.now(),
      createdBy: h.registeredBy,
      _source: 'legacy',
      _fullPaymentHistoryIndex: fullIdx,
    });
  });
  return [...fromField, ...legacy].sort((a, b) => (Number(a.createdAt) || 0) - (Number(b.createdAt) || 0));
}

/** Texto buscable: comentarios generales del registro y notas en abonos del historial. */
function participantMatchesRosterSearchComments(person, searchLower) {
  if (!searchLower) return false;
  for (const c of getGeneralRegistrationCommentsForDisplay(person)) {
    if (String(c?.text || '').toLowerCase().includes(searchLower)) return true;
  }
  for (const h of person?.paymentHistory || []) {
    if (!h || h.kind === 'comment') continue;
    if (String(h.note || '').toLowerCase().includes(searchLower)) return true;
  }
  return false;
}

function usernamesEqualForCommentAuth(a, b) {
  const sa = String(a ?? '').trim();
  const sb = String(b ?? '').trim();
  return sa !== '' && sb !== '' && sa === sb;
}

/** SuperUsuario, Administrador o quien escribió el comentario/nota. */
function userCanDeleteRegistrationComment(c, { currentUser, isSuperUser, hasAdminRights }) {
  if (currentUser?.role === 'Lector') return false;
  if (isSuperUser || hasAdminRights) return true;
  return usernamesEqualForCommentAuth(c?.createdBy, currentUser?.username);
}

function userCanOpenAbonoNoteEditModal(pay, { currentUser, canEditAbonosAndPaymentHistory }) {
  if (currentUser?.role === 'Lector' || !pay || pay.kind === 'comment') return false;
  if (canEditAbonosAndPaymentHistory) return true;
  return usernamesEqualForCommentAuth(pay?.registeredBy, currentUser?.username);
}

function userCanDeleteAbonoNote(pay, { currentUser, isSuperUser, hasAdminRights }) {
  if (currentUser?.role === 'Lector' || !pay || !String(pay.note || '').trim()) return false;
  if (isSuperUser || hasAdminRights) return true;
  return usernamesEqualForCommentAuth(pay?.registeredBy, currentUser?.username);
}

