                        <p className="text-xs text-slate-500 mt-0.5">{cut.count} movimiento{cut.count !== 1 ? 's' : ''}{cut.donations > 0 ? ` + donaciones $${cut.donations.toLocaleString('es-MX', { minimumFractionDigits: 2, maximumFractionDigits: 2 })}` : ''}</p>
